from strands import tool
import boto3
import base64

@tool
def fetch_s3_document(bucket: str, key: str) -> dict:
    """Fetch a document from S3. Returns base64 for PDFs or text for XML."""
    s3 = boto3.client('s3')
    resp = s3.get_object(Bucket=bucket, Key=key)
    body = resp['Body'].read()
    if key.endswith('.xml'):
        return {'type': 'xml', 'content': body.decode('utf-8')}
    return {'type': 'binary', 'content': base64.b64encode(body).decode('utf-8')}

from strands import tool
import xml.etree.ElementTree as ET

@tool
def xml_parse_appraisal(xml_content: str) -> dict:
    """Parse appraisal XML and extract all leaf elements as key-value pairs."""
    root = ET.fromstring(xml_content)
    result = {}
    for elem in root.iter():
        if elem.text and elem.text.strip():
            result[elem.tag] = elem.text.strip()
    return result

from strands import tool
import requests
import xml.etree.ElementTree as ET

@tool
def usps_validate_address(street: str, city: str, state: str, zip_code: str, usps_user_id: str) -> dict:
    """Validate address via USPS Web Tools API."""
    xml_req = f'<AddressValidateRequest USERID="{usps_user_id}"><Address><Address1></Address1><Address2>{street}</Address2><City>{city}</City><State>{state}</State><Zip5>{zip_code}</Zip5><Zip4></Zip4></Address></AddressValidateRequest>'
    resp = requests.get('https://secure.shippingapis.com/ShippingAPI.dll', params={'API': 'Verify', 'XML': xml_req})
    root = ET.fromstring(resp.text)
    error = root.find('.//Error')
    if error is not None:
        return {'match': False, 'error': error.find('Description').text}
    return {'match': True, 'address': {e.tag: e.text for e in root.find('.//Address')}}

from strands import tool
import requests

@tool
def asc_verify_appraiser(first_name: str, last_name: str, state: str) -> dict:
    """Verify appraiser license via ASC National Registry."""
    resp = requests.get('https://www.asc.gov/api/registry/search', params={'firstName': first_name, 'lastName': last_name, 'state': state})
    if resp.status_code == 200:
        data = resp.json()
        return {'found': len(data.get('results', [])) > 0, 'results': data.get('results', [])[:3]}
    return {'found': False, 'error': f'ASC API returned {resp.status_code}'}

from strands import tool
import requests
import boto3

@tool
def google_maps_streetview(address: str, api_key: str, bucket: str, case_id: str) -> dict:
    """Fetch Street View image and upload to S3."""
    url = f'https://maps.googleapis.com/maps/api/streetview?size=640x480&location={address}&key={api_key}'
    resp = requests.get(url)
    if resp.status_code == 200:
        s3_key = f'loanDocs/AppraisalReview/{case_id}/streetview/front.jpg'
        boto3.client('s3').put_object(Bucket=bucket, Key=s3_key, Body=resp.content, ContentType='image/jpeg')
        return {'success': True, 's3_key': s3_key}
    return {'success': False, 'error': f'Google API returned {resp.status_code}'}

from strands import tool
import boto3
import json

@tool
def analyze_photo_bedrock(image_base64: str, prompt: str, model_id: str = 'amazon.nova-pro-v1:0') -> dict:
    """Analyze a photo using Bedrock vision capabilities."""
    client = boto3.client('bedrock-runtime')
    resp = client.converse(modelId=model_id, messages=[{'role': 'user', 'content': [{'image': {'format': 'jpeg', 'source': {'bytes': image_base64}}}, {'text': prompt}]}])
    return {'analysis': resp['output']['message']['content'][0]['text']}

from strands import tool
import boto3
import json

@tool
def evaluate_question_llm(question: str, context: str, model_id: str = 'amazon.nova-pro-v1:0') -> dict:
    """Evaluate a checklist question using Bedrock LLM. Returns answer and confidence."""
    client = boto3.client('bedrock-runtime')
    prompt = f'Given this data:\n{context}\n\nAnswer this question with Yes/No/N-A/Unknown and confidence 0-100:\n{question}\n\nRespond as JSON: {{"answer": "...", "confidence": N, "reasoning": "..."}}'
    resp = client.converse(modelId=model_id, messages=[{'role': 'user', 'content': [{'text': prompt}]}])
    return json.loads(resp['output']['message']['content'][0]['text'])

from strands import tool
import requests

@tool
def save_checklist_results(api_base_url: str, auth_token: str, case_id: str, item_id: str, result: dict) -> dict:
    """Save checklist item result and update case status via API."""
    headers = {'Authorization': f'Bearer {auth_token}', 'Content-Type': 'application/json'}
    resp = requests.post(f'{api_base_url}/api/cases/{case_id}/checklist/{item_id}/update', json=result, headers=headers)
    return {'success': resp.status_code == 200, 'status_code': resp.status_code}

from strands import tool
import requests

@tool
def update_processing_state(api_base_url: str, auth_token: str, case_id: str, stage: str, progress: int) -> dict:
    """Update case processing state with current stage and progress."""
    headers = {'Authorization': f'Bearer {auth_token}', 'Content-Type': 'application/json'}
    resp = requests.post(f'{api_base_url}/api/case-processing/state/{case_id}/update', json={'stage': stage, 'progress': progress}, headers=headers)
    return {'success': resp.status_code == 200, 'status_code': resp.status_code}
